    val greeting: String
        get() {
            return "Hello World!"
        }
}

fun getRequest(url: String): String? {
    val client = OkHttpClient() // TODO move?
    val request = Request.Builder().url(url).build()

    val response = client.newCall(request).execute()
    if (response.code >= 400) {
        throw IOException("request failed, response code = "+response.code)
    }
    return response.body?.string() ?: "{}"
}

fun getFileOrURL(fileOrUrl: String): String? {
    return if (fileOrUrl.startsWith("http")) {
        getRequest(fileOrUrl)
    }
    else {
        File(fileOrUrl).readText()
    }
}

fun getCharacter(arg: String): Character? {
    if (!arg.contains(":")) return null
    val id = arg.split(":")[1]
    val charJson = getFileOrURL("https://character-service.dndbeyond.com/character/v5/character/"+id) ?: "{}"
    //println ("charJson = "+charJson)
    return Json.decodeFromString(charJson)
}

fun getResource(fileName: String): String? {
    val inputStream: InputStream = object {}.javaClass.getResourceAsStream("/$fileName") ?: return null
    try {
        return inputStream.bufferedReader().use { it.readText() }
    } catch (e: Exception) {
        e.printStackTrace()
        return null
    }
}

fun main(args : Array<String>) {
    var exitEarly = false

    if (args.isEmpty()) {
        System.err.println()
        System.err.println("Usage: [-d] [--csv] [file.json ...]  [character]  < dump[:opt] | search<opt> | <attacks> | turns >");
        System.err.println()
        System.err.println("File:")
        System.err.println()
        System.err.println("\t file.json \t load spell or monster data; this is optional: program contains most 2014 and 2024 data")
        System.err.println()
        System.err.println("Character:")
        System.err.println()
        System.err.println("\t NumericID \t read character from DND Beyond API (character must have public visibility)")
        System.err.println("\t file.json \t read character from a local file")
        System.err.println()
        System.err.println("Dump:")
        System.err.println()
        System.err.println("\t dump:spells \t export all known spells");
        System.err.println("\t dump:monsters \t export all known monsters");
        System.err.println("\t dump:attacks \t export attacks from user input");
        System.err.println("\t dump:character\t export (minimal) character data from DND Beyond");
        System.err.println("\t dump \t\t export all of the above");
        System.err.println()
        System.err.println("Search:")
        System.err.println()
        System.err.println("\t search:NAME \t search for NAME in list of spells/monsters, and display details if found");
        System.err.println()
        System.err.println("Attacks:")
        System.err.println()
        System.err.println("\t -a  <monster spellOrWeapon> ...    (multiple pairs allowed)")
        System.err.println()
        System.err.println("Turns:")
        System.err.println()
        System.err.println("\t an array of turns, each with an array of attacks, for example:")
        System.err.println()
        System.err.println("\t\t [ { \"attacks\": [ { \"monster\": \"Goblin\", \"attack\": \"Longbow\" } ] } ]")
        System.err.println()
        System.err.println()
        System.err.println("\t optional notes and preconditions are also supported, for example:")
        System.err.println("""
    [
      {
        "notes": [
            "Turn 1: Assume Mind Sliver was cast prior to this turn",
            "When MS is successful, in addition to 1d6 damage, it imposes a 1d4 penalty on the target's next saving throw"
        ],
        "preconditions": {
            "bonusDiceToSave":       { "d4": 0, "d6": 0, "d8": 0, "d10": 0, "d12": 0 },
            "penaltyDiceToSave":     { "d4": 1, "d6": 0, "d8": 0, "d10": 0, "d12": 0 },
            "bonusDamageOnFirstHit": { "d4": 0, "d6": 0, "d8": 0, "d10": 0, "d12": 0 },
            "bonusDamage": 0
        },
    
        "attacks": [
            { "monster": "Goblin", "attack": "Longbow" },
            { "monster": "Goblin", "attack": "Ensnaring Strike", "isBonusAction": true }
        ]    
      } 
    ]
        """)
        System.err.println()
    }

    val spellResource = getResource("spells.json")
    if (spellResource != null)  spells.addAll(Json.decodeFromString(spellResource))

    val spellResource2 = getResource("extra.spells.json")
    if (spellResource2 != null)  spells.addAll(Json.decodeFromString(spellResource2))

    val monsterResource = getResource("monsters.json")
    if (monsterResource != null)  monsters.addAll(Json.decodeFromString(monsterResource))

    // each arg should be a json file (spells, monsters, character, or attacks) or a debug cmd (dump, search, test)
    //     for (arg in args) {
    for (i in args.indices) {
        val arg = args[i]
        if (arg.startsWith("-")) {
            when (arg) {
                "-d" -> Globals.debug = true
                "--csv" -> outputFormat = "csv"
                "-a" -> {
                    val attackList = mutableListOf<Attack>()
                    for (j in (i+1) until args.size step 2) {
                        val monsterName = args[j]
                        val attackName = args[j+1]
                        attackList.add(Attack(monsterName, attackName))
                    }
                    turns.add(Turn(null, attackList, null))
                    break
                }
                else -> println("invalid argument: $arg")
            }
        }
        else if (arg.endsWith(".json")) {
            val jsonString = getFileOrURL(arg)
            if (jsonString == null) {
                println("unable to read input: $arg")
            }
            else if (jsonString.contains("School")) {
                spells.addAll(Json.decodeFromString(jsonString))
            }
            else if (jsonString.contains("\"Monsters\"")){
                monsters.addAll(Json.decodeFromString(jsonString))
            }
            else if (jsonString.contains("\"monster\"")) {
                turns.addAll(Json.decodeFromString(jsonString))
                scenario = File(arg).nameWithoutExtension
            }
            else if (jsonString.contains("\"username\"")) {
                character = Json.decodeFromString(jsonString)
            }
        }
        else if (arg.endsWith(".json")){
            println("unknown file type: $arg")
        }
        else if (arg.startsWith("character")) {
            character = getCharacter(arg)
        }
        else if (arg.startsWith("dump")) {
            TurnCalculator.dump(arg)
            exitEarly = true
        }
        else if (arg.startsWith("search")) {
            TurnCalculator.search(arg)
            exitEarly = true
        }
        else if (arg.startsWith("test")) {
            character?.test()
            exitEarly = true
        }
    }

    if (exitEarly) {
        // quietly go away
    }
    else if (spells.isEmpty()) {
        println("no spell data")
    }
    else if (monsters.isEmpty()) {
        println("no monsters data")
    }
    else if (character == null) {
        println("no character data")
    }
    else if (turns.isEmpty()) {
        println("no attacks specified")
    }
    else {
        TurnCalculator.calculateDPRForAllTurns()
    }
}
